// ========== ВАЛИДАЦИЯ ВХОДНЫХ ДАННЫХ ==========
const input = $input.first().json;
const body = input.body || input;

// Извлекаем параметры (поддержка разных форматов)
const query = body.query || input.query;
const sessionId = body.sessionId || input.sessionId || `session_${Date.now()}`;
const userId = body.userId || input.userId || 'anonymous';

// === Валидация ===
if (!query || typeof query !== 'string') {
  throw new Error('❌ "query" is required and must be a string');
}

if (query.trim().length < 2) {
  throw new Error('❌ Query must be at least 2 characters');
}

if (query.length > 5000) {
  throw new Error('❌ Query exceeds maximum length of 5000 characters');
}

// === Метаданные для роутинга ===
const metadata = {
  queryLength: query.length,
  wordCount: query.trim().split(/\s+/).length,
  hasQuestion: query.includes('?'),
  hasCode: /```|function|class|const|let|import|export/.test(query),
  isTechnical: /api|database|server|code|function|react|vue|angular|python|javascript/.test(query.toLowerCase()),
  hasUrl: /https?:\/\//.test(query),
  timestamp: new Date().toISOString()
};

// === Уникальный ключ для кеша ===
const cacheKey = `${sessionId}:${query.trim().toLowerCase().slice(0, 100)}`;

console.log('📥 Received query:', { query, sessionId, userId });

return {
  query: query.trim(),
  sessionId,
  userId,
  metadata,
  cacheKey,
  startTime: Date.now()
};

// ========== L1 IN-MEMORY CACHE ==========
// Глобальный кеш (живёт пока работает n8n)
if (!global.ragCache) {
  global.ragCache = new Map();
  global.cacheTimestamps = new Map();
  console.log('🚀 Cache initialized');
}

const CACHE_TTL = 300000; // 5 минут в миллисекундах
const now = Date.now();
const cacheKey = $json.cacheKey;

// === Автоматическая очистка устаревшего кеша ===
if (global.cacheTimestamps.has(cacheKey)) {
  const cachedTime = global.cacheTimestamps.get(cacheKey);
  if (now - cachedTime > CACHE_TTL) {
    global.ragCache.delete(cacheKey);
    global.cacheTimestamps.delete(cacheKey);
    console.log(`🗑️ Cache expired for: ${cacheKey}`);
  }
}

// === Проверяем кеш ===
const cachedResponse = global.ragCache.get(cacheKey);

if (cachedResponse) {
  console.log(`✅ CACHE HIT for: ${cacheKey}`);
  return {
    ...$json,
    cacheHit: true,
    cacheLevel: 'L1',
    response: cachedResponse
  };
}

console.log(`❌ CACHE MISS for: ${cacheKey}`);
return {
  ...$json,
  cacheHit: false,
  cacheLevel: null
};

