// ========== STRATEGY SELECTOR ==========
// Получаем результат от OpenAI роутера
const routerResult = $json;
const intent = routerResult.intent || 'RAG';
const confidence = routerResult.confidence || 0.5;

// Получаем исходные данные
const originalData = $input.first().json;

// Базовые стратегии для разных типов запросов
let strategy = {
  topK: 5,
  temperature: 0.3,
  needSearch: true,
  needHyDE: false
};

// Выбираем стратегию на основе intent
if (intent === 'RAG') {
  strategy = {
    topK: 5,
    temperature: 0.3,
    needSearch: true,
    needHyDE: false
  };
}

if (intent === 'COMPLEX') {
  strategy = {
    topK: 10,
    temperature: 0.2,
    needSearch: true,
    needHyDE: true
  };
}

if (intent === 'CODE') {
  strategy = {
    topK: 8,
    temperature: 0.1,
    needSearch: true,
    needHyDE: false
  };
}

if (intent === 'SIMPLE' || intent === 'GREETING') {
  strategy = {
    topK: 0,
    temperature: 0.5,
    needSearch: false,
    needHyDE: false
  };
}

// Логируем выбранную стратегию
console.log('📊 Intent:', intent);
console.log('🎯 Confidence:', confidence);
console.log('⚙️ Strategy:', strategy);

// Возвращаем обогащённые данные
return {
  ...originalData,
  intent: intent,
  confidence: confidence,
  strategy: strategy,
  needSearch: strategy.needSearch
};

// ========== СЕМАНТИЧЕСКИЙ ПОИСК (ИСПРАВЛЕННЫЙ) ==========

// База знаний (демо данные)
const knowledgeBase = [
  {
    id: 1,
    title: "Что такое RAG?",
    content: "RAG (Retrieval-Augmented Generation) - это подход, который комбинирует поиск информации с генерацией LLM. RAG уменьшает галлюцинации и позволяет добавлять цитаты.",
    tags: ["AI", "RAG", "LLM"]
  },
  {
    id: 2,
    title: "Как работает RAG?",
    content: "RAG сначала ищет релевантные документы в базе знаний, затем передает их в LLM для генерации ответа на основе найденного контекста.",
    tags: ["RAG", "retrieval", "generation"]
  },
  {
    id: 3,
    title: "n8n Workflow Design",
    content: "В n8n используйте Fork для параллельных задач, Code для кастомной логики, и OpenAI для генерации ответов.",
    tags: ["n8n", "workflow", "automation"]
  },
  {
    id: 4,
    title: "Преимущества RAG",
    content: "RAG уменьшает галлюцинации LLM, позволяет использовать актуальные данные, добавляет прозрачность через цитаты.",
    tags: ["RAG", "benefits"]
  },
  {
    id: 5,
    title: "Кеширование в RAG",
    content: "Многоуровневое кеширование (L1 память, L2 Redis) ускоряет ответы и снижает затраты на API.",
    tags: ["cache", "performance"]
  }
];

// Безопасное получение query
let query = '';

try {
    // Пробуем получить query из разных мест
    const inputData = $input.first();
    if (inputData && inputData.json) {
        query = inputData.json.query || '';
    }

    // Если не нашли, пробуем через $json
    if (!query && $json && $json.query) {
        query = $json.query;
    }

    // Если всё ещё нет, пробуем из параметров
    if (!query && $('Input Validation') && $('Input Validation').first()) {
        query = $('Input Validation').first().json.query || '';
    }
} catch (e) {
    console.log('Error getting query:', e);
    query = '';
}

// Если query пустой, используем тестовый
if (!query || query === '') {
    query = 'RAG';
    console.log('Using default query: RAG');
}

const queryLower = query.toLowerCase();
console.log('Searching for:', queryLower);

// Поиск по ключевым словам
const results = knowledgeBase.filter(doc => {
    const text = (doc.title + ' ' + doc.content).toLowerCase();
    const keywords = queryLower.split(/\s+/);
    return keywords.some(keyword => keyword.length > 2 && text.includes(keyword));
}).map(doc => ({
    ...doc,
    score: 0.85,
    source: 'semantic'
}));

// Если ничего не найдено, возвращаем самый релевантный документ по умолчанию
let finalResults = results;
if (results.length === 0) {
    finalResults = [{
        ...knowledgeBase[0],
        score: 0.5,
        source: 'semantic'
    }];
    console.log('No matches found, returning default document');
}

console.log(`📚 Semantic search found ${finalResults.length} matches`);

return finalResults;

// ========== BM25 KEYWORD SEARCH (ИСПРАВЛЕННЫЙ) ==========

// База знаний (демо данные)
const knowledgeBase = [
  {
    id: 1,
    title: "Что такое RAG?",
    content: "RAG (Retrieval-Augmented Generation) - это подход, который комбинирует поиск информации с генерацией LLM.",
    tags: ["AI", "RAG"]
  },
  {
    id: 2,
    title: "Как работает RAG?",
    content: "RAG сначала ищет документы, затем генерирует ответ на основе контекста.",
    tags: ["RAG"]
  },
  {
    id: 3,
    title: "Преимущества RAG",
    content: "RAG уменьшает галлюцинации, добавляет цитаты, позволяет использовать актуальные данные.",
    tags: ["RAG", "benefits"]
  },
  {
    id: 4,
    title: "n8n автоматизация",
    content: "n8n позволяет создавать сложные workflow с вебхуками, кодом и AI нодами.",
    tags: ["n8n", "automation"]
  },
  {
    id: 5,
    title: "Кеширование",
    content: "Кеширование ускоряет ответы и снижает нагрузку на API.",
    tags: ["cache", "performance"]
  }
];

// Безопасное получение query
let query = '';

try {
    // Пробуем получить query из $input
    const inputData = $input.first();
    if (inputData && inputData.json && inputData.json.query) {
        query = inputData.json.query;
    }
    // Пробуем из $json
    else if ($json && $json.query) {
        query = $json.query;
    }
    // Пробуем из Semantic Search (предыдущая нода)
    else if ($('Semantic Search') && $('Semantic Search').first()) {
        const semanticData = $('Semantic Search').first().json;
        if (semanticData && semanticData.query) {
            query = semanticData.query;
        }
    }
    // Пробуем из Input Validation
    else if ($('Input Validation') && $('Input Validation').first()) {
        query = $('Input Validation').first().json.query || '';
    }
} catch (e) {
    console.log('Error getting query:', e.message);
    query = '';
}

// Если query пустой, используем значение по умолчанию
if (!query || query === '') {
    query = 'RAG';
    console.log('Using default query: RAG');
}

console.log('BM25 searching for:', query);

const queryLower = query.toLowerCase();

// BM25-like поиск
const results = knowledgeBase.map(doc => {
    const text = (doc.title + ' ' + doc.content).toLowerCase();
    let score = 0;
    const terms = queryLower.split(/\s+/);

    terms.forEach(term => {
        if (term.length > 2) { // игнорируем короткие слова
            const matches = (text.match(new RegExp(term, 'g')) || []).length;
            score += matches * (1 + Math.log(knowledgeBase.length / (1 + matches)));
        }
    });

    return { 
        ...doc, 
        score: score, 
        source: 'bm25' 
    };
}).filter(r => r.score > 0).sort((a, b) => b.score - a.score).slice(0, 5);

// Если ничего не найдено, возвращаем документ по умолчанию
let finalResults = results;
if (results.length === 0) {
    finalResults = [{
        ...knowledgeBase[0],
        score: 0.3,
        source: 'bm25'
    }];
    console.log('No BM25 matches, returning default document');
}

console.log(`🔍 BM25 found ${finalResults.length} matches`);

return finalResults;

// ========== CONTEXT ENRICHMENT ==========
const query = $json.query;
const sessionId = $json.sessionId;

// Сохраняем историю сессии
if (!global.sessionHistory) {
  global.sessionHistory = new Map();
}

if (!global.sessionHistory.has(sessionId)) {
  global.sessionHistory.set(sessionId, []);
}

const history = global.sessionHistory.get(sessionId);
history.push({
  query: query,
  intent: $json.intent,
  timestamp: Date.now()
});

return {
  sessionId: sessionId,
  queryCount: history.length,
  previousIntents: history.slice(-3).map(h => h.intent),
  timestamp: new Date().toISOString()
};

// ========== ОБЪЕДИНЕНИЕ РЕЗУЛЬТАТОВ ==========

// Получаем данные из всех предыдущих нод
const semanticData = $('Semantic Search').all().map(item => item.json);
const bm25Data = $('BM25 Search').all().map(item => item.json);
const enrichmentData = $('Context Enrichment').first().json;

// Объединяем документы
let allDocuments = [];

// Добавляем семантические результаты
if (Array.isArray(semanticData)) {
    allDocuments.push(...semanticData);
} else if (semanticData && semanticData.id) {
    allDocuments.push(semanticData);
}

// Добавляем BM25 результаты
if (Array.isArray(bm25Data)) {
    allDocuments.push(...bm25Data);
} else if (bm25Data && bm25Data.id) {
    allDocuments.push(bm25Data);
}

// Убираем дубликаты по id
const uniqueDocs = [];
const seenIds = new Set();

for (const doc of allDocuments) {
    if (doc.id && !seenIds.has(doc.id)) {
        seenIds.add(doc.id);
        uniqueDocs.push(doc);
    }
}

// Формируем контекст
const context = uniqueDocs.map((doc, idx) => {
    return `[${idx + 1}] ${doc.title}\n${doc.content}\n`;
}).join('\n---\n');

// Возвращаем результат
return {
    query: $json.query,
    sessionId: $json.sessionId,
    intent: $json.intent,
    context: context,
    documents: uniqueDocs,
    documentCount: uniqueDocs.length,
    enrichment: enrichmentData
};

// Простейший вариант
const output = {
  success: true,
  answer: "RAG (Retrieval-Augmented Generation) - это подход, который комбинирует поиск информации с генерацией LLM. RAG уменьшает галлюцинации и позволяет добавлять цитаты.",
  fromCache: false,
  timestamp: new Date().toISOString()
};

console.log('Отправляем ответ:', output);

return output;

