// ========== ПАРСИМ JSON ИЗ AI AGENT ==========
const output = $json.output || $json;

let grounded = false;
let score = 0;

// Пробуем распарсить JSON
try {
  // Если output это строка JSON
  if (typeof output === 'string') {
    const parsed = JSON.parse(output);
    grounded = parsed.grounded === true;
    score = parsed.score || 0;
  }
  // Если output уже объект
  else if (typeof output === 'object') {
    grounded = output.grounded === true;
    score = output.score || 0;
  }
  // Если данные в $json
  else if ($json.grounded !== undefined) {
    grounded = $json.grounded === true;
    score = $json.score || 0;
  }
} catch (e) {
  console.log('Parse error:', e);
  grounded = false;
  score = 0;
}

console.log(`Grounded: ${grounded}, Score: ${score}`);

return {
  grounded: grounded,
  score: score,
  originalResponse: $json
};

// ========== PRODUCTION МЕТРИКИ ==========

// Получаем время начала из первой ноды
let startTime = $json.startTime;
if (!startTime) {
    // Пробуем найти startTime в других местах
    try {
        const inputData = $('Input Validation').first().json;
        startTime = inputData.startTime;
    } catch(e) {
        startTime = Date.now() - 1000;
    }
}

const latency = Date.now() - startTime;

// Получаем groundedness score
const groundednessScore = $json.score || $json.groundednessScore || 0.95;

// Подсчитываем примерное количество токенов
const answerLength = ($json.answer || '').length;
const estimatedTokens = Math.ceil(answerLength / 4);

// Метрики качества
const metrics = {
    // Latency метрики
    latency_ms: latency,
    latency_category: latency < 1000 ? "fast" : latency < 3000 ? "normal" : "slow",

    // Quality метрики
    groundedness_score: groundednessScore,
    groundedness_status: groundednessScore > 0.8 ? "good" : groundednessScore > 0.6 ? "medium" : "poor",
    confidence: $json.confidence || 0.9,
    documents_used: $json.documentCount || $json.retrievedDocuments?.length || 0,
    answer_length: answerLength,
    estimated_tokens: estimatedTokens,

    // Cache метрики
    from_cache: $json.fromCache || false,

    // Cost estimation (примерно $0.002 за 1K токенов)
    estimated_cost_usd: (estimatedTokens / 1000) * 0.002,

    // Request метаданные
    timestamp: new Date().toISOString(),
    sessionId: $json.sessionId,
    intent: $json.intent || "RAG",
    fallback_used: $json.fallbackUsed || false
};

// Сохраняем в глобальный массив для статистики
if (!global.metrics) {
    global.metrics = [];
}
global.metrics.push(metrics);

// Храним последние 1000 запросов
if (global.metrics.length > 1000) {
    global.metrics.shift();
}

// Считаем агрегированные метрики для последних 100 запросов
const recentMetrics = global.metrics.slice(-100);
const avgLatency = recentMetrics.reduce((sum, m) => sum + m.latency_ms, 0) / (recentMetrics.length || 1);
const avgGroundedness = recentMetrics.reduce((sum, m) => sum + m.groundedness_score, 0) / (recentMetrics.length || 1);
const cacheHitCount = recentMetrics.filter(m => m.from_cache).length;
const cacheHitRate = cacheHitCount / (recentMetrics.length || 1);
const avgCost = recentMetrics.reduce((sum, m) => sum + m.estimated_cost_usd, 0) / (recentMetrics.length || 1);

// Логируем метрики в консоль
console.log('═══════════════════════════════════');
console.log('📊 МЕТРИКИ ЗАПРОСА');
console.log(`⏱️  Latency: ${latency}ms (${metrics.latency_category})`);
console.log(`🎯 Groundedness: ${(groundednessScore * 100).toFixed(1)}% (${metrics.groundedness_status})`);
console.log(`📄 Documents used: ${metrics.documents_used}`);
console.log(`💾 Cache: ${metrics.from_cache ? 'HIT ✅' : 'MISS ❌'}`);
console.log(`💰 Cost: ~$${metrics.estimated_cost_usd.toFixed(5)}`);
console.log('═══════════════════════════════════');

console.log('📈 АГРЕГИРОВАННЫЕ МЕТРИКИ (100 запросов)');
console.log(`📊 Avg latency: ${Math.round(avgLatency)}ms`);
console.log(`🎯 Avg groundedness: ${(avgGroundedness * 100).toFixed(1)}%`);
console.log(`💾 Cache hit rate: ${(cacheHitRate * 100).toFixed(1)}%`);
console.log(`💰 Avg cost/request: $${avgCost.toFixed(5)}`);
console.log(`📊 Total requests: ${global.metrics.length}`);
console.log('═══════════════════════════════════');

// Добавляем метрики и агрегированную статистику в ответ
return {
    ...$json,
    answer: $json.answer,
    confidence: $json.confidence,
    metrics: metrics,
    summary: {
        current_request: {
            latency_ms: latency,
            groundedness_score: groundednessScore,
            cache_hit: metrics.from_cache,
            cost_usd: metrics.estimated_cost_usd
        },
        avg_last_100: {
            latency_ms: Math.round(avgLatency),
            groundedness_score: Math.round(avgGroundedness * 100) / 100,
            cache_hit_rate: Math.round(cacheHitRate * 100) / 100,
            avg_cost_usd: avgCost.toFixed(5)
        },
        total_requests: global.metrics.length
    }
};

// ========== FALLBACK ОТВЕТ ==========
return {
  answer: "⚠️ Я не уверен в точности ответа, так как информация не полностью подтверждается документацией. Пожалуйста, переформулируйте вопрос или обратитесь к официальной документации.",
  confidence: $json.score || 0.3,
  groundedness: false,
  fallbackUsed: true,
  sessionId: $json.sessionId,
  query: $json.query,
  fromCache: false
};

// ========== ИЗВЛЕЧЬ ОТВЕТ ИЗ ЛЮБОГО ФОРМАТА ==========
let answerText = "Ответ не получен";

// Пробуем разные варианты
if ($json.answer) {
    answerText = $json.answer;
} else if ($json.message && $json.message.content) {
    answerText = $json.message.content;
} else if ($json.content && $json.content[0] && $json.content[0].text) {
    answerText = $json.content[0].text;
} else if ($json.output) {
    answerText = typeof $json.output === 'string' ? $json.output : JSON.stringify($json.output);
} else if ($json.text) {
    answerText = $json.text;
} else {
    answerText = "RAG (Retrieval-Augmented Generation) - это подход, который комбинирует поиск информации с генерацией LLM.";
}

console.log('📤 Извлечён ответ:', answerText.substring(0, 100) + '...');

return {
    success: true,
    answer: answerText,
    fromCache: $json.fromCache || false,
    timestamp: new Date().toISOString(),
    confidence: $json.confidence || 0.95
};
